import{_ as e,c as s,o as a,aN as n}from"./chunks/framework.CqA5BTDU.js";const b=JSON.parse('{"title":"K8s监控基础","description":"","frontmatter":{},"headers":[],"relativePath":"12.可观测性与监控告警/11-K8s监控基础.md","filePath":"12.可观测性与监控告警/11-K8s监控基础.md","lastUpdated":null}'),p={name:"12.可观测性与监控告警/11-K8s监控基础.md"};function d(r,t,o,l,c,i){return a(),s("div",null,[...t[0]||(t[0]=[n(`<h1 id="k8s监控基础" tabindex="-1">K8s监控基础 <a class="header-anchor" href="#k8s监控基础" aria-label="Permalink to &quot;K8s监控基础&quot;">​</a></h1><p>Kubernetes 监控和传统主机监控不一样。传统主机监控通常围绕 CPU、内存、磁盘、网络展开；K8s 还要关心控制平面、节点组件、Pod、容器、Workload、Service、PVC、事件和业务指标。</p><p>Kubernetes 监控面向集群资源和控制面状态，采集对象从单台 Linux 主机扩展到 Node、Pod、Workload、kubelet、cAdvisor、kube-state-metrics、CoreDNS 和 API Server。K3s 集群的搭建见 <a href="/kb/10.Kubernetes/05-K3s安装部署">K3s 安装部署</a>。一个 Pod 没有起来，可能是镜像拉取失败、调度失败、PVC 没绑定、探针失败、节点压力、NetworkPolicy 拦截，也可能是应用自己启动失败。</p><p>指标链路要覆盖三类问题：</p><table tabindex="0"><thead><tr><th>问题</th><th>指标来源</th></tr></thead><tbody><tr><td>集群和节点是否健康</td><td>API Server、kubelet、node-exporter、CoreDNS</td></tr><tr><td>资源对象是否达到期望状态</td><td>kube-state-metrics</td></tr><tr><td>容器和业务是否运行正常</td><td>kubelet/cAdvisor、应用 <code>/metrics</code></td></tr></tbody></table><h2 id="一、指标来源" tabindex="-1">一、指标来源 <a class="header-anchor" href="#一、指标来源" aria-label="Permalink to &quot;一、指标来源&quot;">​</a></h2><p>K8s 里常见指标来源如下：</p><table tabindex="0"><thead><tr><th>来源</th><th>典型指标</th><th>说明</th></tr></thead><tbody><tr><td>API Server</td><td>请求量、延迟、错误码</td><td>控制平面入口</td></tr><tr><td>kubelet</td><td>Pod 生命周期、volume、probe、容器资源</td><td>每台节点上的节点代理</td></tr><tr><td>cAdvisor</td><td>容器 CPU、内存、网络、文件系统</td><td>kubelet 内置容器指标</td></tr><tr><td>node-exporter</td><td>主机 CPU、内存、磁盘、网络、文件描述符</td><td>Linux 主机层</td></tr><tr><td>kube-state-metrics</td><td>Pod、Deployment、PVC、Job 等对象状态</td><td>反映 apiserver 里的对象状态</td></tr><tr><td>CoreDNS</td><td>DNS 请求量、错误、延迟</td><td>集群服务发现</td></tr><tr><td>应用 <code>/metrics</code></td><td>QPS、错误率、延迟、业务指标</td><td>应用自己暴露</td></tr><tr><td>etcd</td><td>leader、proposal、fsync、DB size</td><td>控制平面数据存储</td></tr></tbody></table><p>当前 K3s 是默认 SQLite，etcd 指标不在这套集群里采集。etcd 监控需要切到 embedded etcd 场景单独记录。</p><h2 id="二、节点指标和对象指标" tabindex="-1">二、节点指标和对象指标 <a class="header-anchor" href="#二、节点指标和对象指标" aria-label="Permalink to &quot;二、节点指标和对象指标&quot;">​</a></h2><p>节点指标说明机器资源，来自 node-exporter 和 kubelet/cAdvisor。比如：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 三台节点是否都被 node-exporter 采到</span></span>
<span class="line"><span>count(node_uname_info)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 节点内存可用比例</span></span>
<span class="line"><span>node_memory_MemAvailable_bytes / node_memory_MemTotal_bytes</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 容器 CPU 使用</span></span>
<span class="line"><span>sum by (namespace, pod, container) (</span></span>
<span class="line"><span>  rate(container_cpu_usage_seconds_total{container!=&quot;&quot;, image!=&quot;&quot;}[5m])</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>对象指标说明 Kubernetes 资源当前状态，来自 kube-state-metrics。比如：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># Pod 信息数量</span></span>
<span class="line"><span>count(kube_pod_info)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Deployment 可用副本和期望副本</span></span>
<span class="line"><span>kube_deployment_status_replicas_available</span></span>
<span class="line"><span>kube_deployment_spec_replicas</span></span>
<span class="line"><span></span></span>
<span class="line"><span># Pod 重启次数</span></span>
<span class="line"><span>increase(kube_pod_container_status_restarts_total[15m])</span></span></code></pre></div><p>节点 CPU 高和 Deployment 副本不足不是同一类问题。前者偏资源压力，后者偏对象状态。排查时经常两边一起看：节点是否有压力，Pod 是否被调度，容器是否启动，Workload 是否达到期望副本数。</p><h2 id="三、kube-state-metrics-的作用" tabindex="-1">三、kube-state-metrics 的作用 <a class="header-anchor" href="#三、kube-state-metrics-的作用" aria-label="Permalink to &quot;三、kube-state-metrics 的作用&quot;">​</a></h2><p>kube-state-metrics 不采集容器 CPU、内存，它读取 Kubernetes API 里的对象状态，再转成 Prometheus 指标。它更像是把 <code>kubectl get</code> 看到的对象状态变成时间序列。</p><p>典型指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>含义</th></tr></thead><tbody><tr><td><code>kube_pod_status_phase</code></td><td>Pod 当前阶段</td></tr><tr><td><code>kube_pod_container_status_restarts_total</code></td><td>容器重启次数</td></tr><tr><td><code>kube_deployment_spec_replicas</code></td><td>Deployment 期望副本</td></tr><tr><td><code>kube_deployment_status_replicas_available</code></td><td>Deployment 可用副本</td></tr><tr><td><code>kube_persistentvolumeclaim_status_phase</code></td><td>PVC 状态</td></tr><tr><td><code>kube_node_status_condition</code></td><td>Node condition</td></tr></tbody></table><p>Pod Pending、Deployment 副本不足、PVC 一直 Pending、Job 失败这类问题，都要看 kube-state-metrics。</p><h2 id="四、kubelet-和-cadvisor" tabindex="-1">四、kubelet 和 cAdvisor <a class="header-anchor" href="#四、kubelet-和-cadvisor" aria-label="Permalink to &quot;四、kubelet 和 cAdvisor&quot;">​</a></h2><p>kubelet 暴露多个 metrics 路径：</p><table tabindex="0"><thead><tr><th>路径</th><th>内容</th></tr></thead><tbody><tr><td><code>/metrics</code></td><td>kubelet 自身指标</td></tr><tr><td><code>/metrics/cadvisor</code></td><td>容器资源指标</td></tr><tr><td><code>/metrics/probes</code></td><td>探针相关指标</td></tr></tbody></table><p>kube-prometheus-stack 里通常会为 kubelet 生成多组 target。本次部署里三台节点的 kubelet、cAdvisor 和 probes target 都是 <code>UP</code>。</p><p>容器资源常用查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 按 Pod 汇总 CPU</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  rate(container_cpu_usage_seconds_total{container!=&quot;&quot;, image!=&quot;&quot;}[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 按 Pod 汇总内存 working set</span></span>
<span class="line"><span>sum by (namespace, pod) (</span></span>
<span class="line"><span>  container_memory_working_set_bytes{container!=&quot;&quot;, image!=&quot;&quot;}</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 容器文件系统使用</span></span>
<span class="line"><span>container_fs_usage_bytes{container!=&quot;&quot;, image!=&quot;&quot;}</span></span></code></pre></div><p><code>kubectl top</code> 也来自 metrics-server，但它更像现场快照。Prometheus 适合看趋势、设置告警、关联看板。</p><h2 id="五、控制平面指标" tabindex="-1">五、控制平面指标 <a class="header-anchor" href="#五、控制平面指标" aria-label="Permalink to &quot;五、控制平面指标&quot;">​</a></h2><p>控制平面至少关注 API Server 和 CoreDNS。K3s 单 server 环境里，API Server 通过 <code>6443</code> 暴露，Prometheus 可以抓到 <code>apiserver_request_total</code> 这类指标。Scheduler 和 Controller Manager 在 K3s 里被打包在 <code>k3s server</code> 进程中，默认监听回环地址，采集方式和 kubeadm 静态 Pod 不完全一样。</p><p>API Server 常用查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># API Server 请求量</span></span>
<span class="line"><span>sum by (verb, resource, code) (</span></span>
<span class="line"><span>  rate(apiserver_request_total[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 5xx 请求</span></span>
<span class="line"><span>sum by (resource, verb) (</span></span>
<span class="line"><span>  rate(apiserver_request_total{code=~&quot;5..&quot;}[5m])</span></span>
<span class="line"><span>)</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 请求延迟 P99</span></span>
<span class="line"><span>histogram_quantile(</span></span>
<span class="line"><span>  0.99,</span></span>
<span class="line"><span>  sum by (le, verb, resource) (</span></span>
<span class="line"><span>    rate(apiserver_request_duration_seconds_bucket[5m])</span></span>
<span class="line"><span>  )</span></span>
<span class="line"><span>)</span></span></code></pre></div><p>CoreDNS 常用查询：</p><div class="language-promql vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">promql</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># DNS 请求量</span></span>
<span class="line"><span>sum(rate(coredns_dns_requests_total[5m]))</span></span>
<span class="line"><span></span></span>
<span class="line"><span># DNS 响应码</span></span>
<span class="line"><span>sum by (rcode) (</span></span>
<span class="line"><span>  rate(coredns_dns_responses_total[5m])</span></span>
<span class="line"><span>)</span></span></code></pre></div><h2 id="六、应用指标" tabindex="-1">六、应用指标 <a class="header-anchor" href="#六、应用指标" aria-label="Permalink to &quot;六、应用指标&quot;">​</a></h2><p>应用指标通常由业务服务自己暴露 <code>/metrics</code>，再用 ServiceMonitor 或 PodMonitor 接入。应用指标和平台指标要能通过 <code>namespace</code>、<code>service</code>、<code>pod</code>、<code>env</code> 这类标签关联。</p><p>常见业务指标：</p><table tabindex="0"><thead><tr><th>指标</th><th>说明</th></tr></thead><tbody><tr><td>请求量</td><td>QPS、接口调用次数</td></tr><tr><td>错误率</td><td>5xx、业务错误码</td></tr><tr><td>延迟</td><td>P50/P95/P99</td></tr><tr><td>队列长度</td><td>异步任务积压</td></tr><tr><td>依赖状态</td><td>数据库、缓存、外部 HTTP 调用</td></tr></tbody></table><p>只看 Pod CPU 和内存不能说明应用是否健康。服务可能资源正常，但错误率已经升高；也可能 CPU 高是因为流量上来了，错误率和延迟仍然正常。</p><h2 id="七、排查顺序" tabindex="-1">七、排查顺序 <a class="header-anchor" href="#七、排查顺序" aria-label="Permalink to &quot;七、排查顺序&quot;">​</a></h2><p>K8s 指标异常可以按这个顺序看：</p><table tabindex="0"><thead><tr><th>层级</th><th>检查点</th></tr></thead><tbody><tr><td>Node</td><td>节点 Ready、CPU、内存、磁盘、网络</td></tr><tr><td>kubelet</td><td>kubelet target、容器资源、probe</td></tr><tr><td>Workload</td><td>Deployment/StatefulSet 副本是否达到期望</td></tr><tr><td>Pod</td><td>phase、restart、waiting reason、OOM</td></tr><tr><td>Service</td><td>endpoints 是否存在</td></tr><tr><td>控制平面</td><td>API Server 延迟、错误、CoreDNS</td></tr><tr><td>应用</td><td>QPS、错误率、P95/P99</td></tr></tbody></table><p>Prometheus 的 Targets 页面是第一入口。target <code>DOWN</code> 时，先解决采集链路；target <code>UP</code> 但指标异常时，再进入 PromQL 和业务排查。</p>`,42)])])}const h=e(p,[["render",d]]);export{b as __pageData,h as default};
